  "Biolab": {"s":58,"t":"C","y":["Crescent Research","AI Central"],"w":"Only when you need the Science tag to unlock something critical in gen 1, or your other preludes are truly terrible.","e":"1 plant-prod = 8 MC, 3 random cards = 9-12 MC"},
  "Early Settlement": {"s":50,"t":"D","y":["Tharsis Republic","Rover Construction","Capital"],"w":"Only on Tharsis for Mayor milestone or if you can grab Olympus Mons on Elysium. Otherwise skip.","e":"1 plant-prod = 8 MC, city tile = ~5-10 MC (placement bonus + future adjacency)"},
  "Colony Trade Hub": {"s":66,"t":"C","y":["Poseidon","Aridor","Trade Fleet"],"w":"Only in 4-5 player games with aggressive colony placement. In 3P, almost never reaches average value.","e":"1 energy-prod = 7"},
