  "Io Research Outpost": {"s":56,"t":"C","y":["Saturn Systems","Rim Settler","Terraforming Ganymede","Io Mining Industries"],"w":"Only with Saturn Systems or when both Jovian+Science tags are critical for your strategy.","e":"1 ti-prod = 12"},
