  "Galilean Mining": {"s":42,"t":"D","y":["Saturn Systems","Terraforming Ganymede","Io Mining Industries"],"w":"Only with Saturn Systems or when you need Jovian tag for Rim Settler. Otherwise one of the weakest preludes.","e":"2 ti-prod = 25 MC theoretical"},
  "Biofuels": {"s":40,"t":"D","y":["Ecoline","Electro Catapult","Splice"],"w":"Almost never. Only if you desperately need energy prod and nothing better is available.","e":"1 energy-prod = 7"},
