  "Nitrogen Shipment": {"s":36,"t":"D","y":["Decomposers","Ants","Herbivores","Virus"],"w":"Almost never. Only when all other options are truly terrible.","e":"1 plant-prod = 8 MC, 1 TR = 7 MC, 5 MC immediate"},
  "Society Support": {"s":30,"t":"F","y":["Caretaker Contract","GHG Factories"],"w":"Never. There is virtually no scenario where this is the right pick.","e":"1 plant-prod = 8 MC, 1 energy-prod = 7"},
  "Space Port Colony": {"s":93,"t":"S","y":["L1 Trade Terminal","Rim Freighters","Trade Envoys"],"w":"Always draft, always play. One of the 3 best cards in the game with colonies.","e":"30 MC total (27+3) for colony + double colony + trade fleet + VP/2 colonies (~3-5 VP in 3P)"},
  "Research Colony": {"s":87,"t":"A","y":["Mars University","Olympus Conference","AI Central","Rim Freighters"],"w":"Always draft, always buy. Play ASAP to maximize double colony value. One of the best cards in the entire game.","e":"23 MC total (20+3) for colony + 2 cards (~8 MC) + Science+Space tags (~5 MC)"},
  "Sky Docks": {"s":91,"t":"S","y":["Cryo-Sleep","Rim Freighters"],"w":"Always draft. Play ASAP when 2 Earth tags met. Top 5 card in colony games.","e":"21 MC total (18+3) for extra trade fleet (~10+ MC/gen) + -1 MC/card discount (~2-3 MC/gen) + 2 VP..."},
  "Nitrogen-Rich Asteroid": {"s":90,"t":"S","y":["Ecoline","Arctic Algae","Adapted Lichen","Moss","Research Network"],"w":"Always draft. With 2+ plant tags, start planning to meet the 3-tag threshold. Without plant tags, still decent for TR...","e":"Cost 31+3=34 MC (ti payable)"},
