  "Earth Catapult": {"s":88,"t":"A","y":["Credicor","Earth Office"],"w":"Almost always in gen 1-4. Even gen 5 can be worth it with strong card draw. Top 3 draft priority.","e":"23 MC + 3 MC card = 26 MC cost"},
  "Mars University": {"s":88,"t":"A","y":["Olympus Conference","AI Central","Research","Cutting Edge Technology"],"w":"Always. First-pick caliber in most drafts. Play as early as possible to maximize cycling value.","e":"Cost 8+3=11 MC (steel payable)"},
