  "Olympus Conference": {"s":85,"t":"A","y":["Mars University","AI Central","Research","Cutting Edge Technology"],"w":"Always. High first-pick priority. Play early to maximize card draw. The triple-tag is unmatched.","e":"Cost 10+3=13 MC (steel payable)"},
  "Giant Ice Asteroid": {"s":84,"t":"A","y":["Advanced Alloys","Arctic Algae","Optimal Aerobraking"],"w":"Almost always when seen. Especially powerful when ocean placement bonuses and temperature bonuses are available.","e":"36 MC (ti payable) + 3 MC card = 39 MC cost"},
