  "Cutting Edge Technology": {"s":84,"t":"A","y":["Adaptation Technology","Special Design","Mars University","Olympus Conference","Research"],"w":"Always pick gen 1-3 if offered. Counter-draft priority. Even gen 4-5 with 3+ requirement cards in hand it is worth it...","e":"12+3=15 MC for -2 MC per requirement card + 1 VP (5 MC) + Science tag (3-5 MC)"},
  "Ecological Zone": {"s":83,"t":"A","y":["Viral Enhancers","Decomposers","Advanced Ecosystems","Imported Nitrogen","Large Convoy"],"w":"High priority whenever you have or plan for a greenery. Core card for bio-tag strategies. Hate-draft from plant players.","e":"12 MC + 3 MC card = 15 MC cost"},
  "AI Central": {"s":82,"t":"A","y":["Mars University","Olympus Conference","Mass Converter","Earth Catapult","Anti-Gravity Technology"],"w":"When you already have 2+ Science tags and energy production, and expect a longer game. Counter-draft to deny engine p...","e":"21+3=24 MC (steel-payable) + ~7 MC energy-prod = 31 MC effective"},
  "Deimos Down": {"s":82,"t":"A","y":["Advanced Alloys","Media Group","Optimal Aerobraking"],"w":"Almost always when seen. Best early for heat production bonuses, but good at any point for efficient temperature rush...","e":"31 MC (ti payable) + 3 MC card = 34 MC cost"},
