  "Ganymede Colony": {"s":75,"t":"B","y":["Io Mining Industries","Vesta Shipyard","Callisto Penal Mines"],"w":"Late game with 3+ Jovian tags. The more Jovian tags you have, the higher priority.","e":"20 MC (ti payable) + 3 MC card = 23 MC cost"},
