  "Mass Converter": {"s":75,"t":"B","y":["Research","Mars University","Olympus Conference","Physics Complex","Warp Drive"],"w":"When you already have 3+ science tags and plan to play more. Keep in hand speculatively if drawn early with science p...","e":"Cost 8+3=11 MC"},
  "Mohole Area": {"s":75,"t":"B","y":["Robotic Workforce","Credicor"],"w":"Gen 1-2 as terraforming anchor. Steel payable makes it very efficient. Late game it's too slow.","e":"Cost 20+3=23 MC (steel payable)"},
